static void dump_hex_bytes(const byte* buf, word32 sz)
{
    word32 i;
    /* Print as : separated hex bytes - max 15 bytes per line */
    printf("\t");
    for (i=0; i<sz; i++) {
        printf("%02x", buf[i]);
        if (i+1 < sz) {
            printf(":");
            if (i>0 && ((i+1)%16)==0) printf("\n\t");
        }
    }
    printf("\n");
}

/* Display EK public information */
static void show_ek_public(const TPM2B_PUBLIC* pub)
{
    printf("EK %s, Hash: %s, objAttr: 0x%X\n",
        TPM2_GetAlgName(pub->publicArea.type),
        TPM2_GetAlgName(pub->publicArea.nameAlg),
        (unsigned int)pub->publicArea.objectAttributes);

    /* parameters and unique field depend on algType */
    if (pub->publicArea.type == TPM_ALG_RSA) {
        printf("\tKeyBits: %d, exponent: 0x%X, unique size %d\n",
            pub->publicArea.parameters.rsaDetail.keyBits,
            (unsigned int)pub->publicArea.parameters.rsaDetail.exponent,
            pub->publicArea.unique.rsa.size);
        dump_hex_bytes(pub->publicArea.unique.rsa.buffer,
                       pub->publicArea.unique.rsa.size);
    }
    else if (pub->publicArea.type == TPM_ALG_ECC) {
        const char* curveName = "NULL";
    #if !defined(WOLFTPM2_NO_WOLFCRYPT) && defined(HAVE_ECC)
        curveName = wc_ecc_get_name(
            TPM2_GetWolfCurve(pub->publicArea.parameters.eccDetail.curveID));
    #endif
        printf("\tCurveID %s (0x%x), size %d, unique X/Y size %d/%d\n",
            curveName, pub->publicArea.parameters.eccDetail.curveID,
            TPM2_GetCurveSize(pub->publicArea.parameters.eccDetail.curveID),
            pub->publicArea.unique.ecc.x.size,
            pub->publicArea.unique.ecc.y.size);
        dump_hex_bytes(pub->publicArea.unique.ecc.x.buffer,
                       pub->publicArea.unique.ecc.x.size);
        dump_hex_bytes(pub->publicArea.unique.ecc.y.buffer,
                       pub->publicArea.unique.ecc.y.size);
    }
}

static int DecodeAsn1Tag(const uint8_t* input, int inputSz, int* inOutIdx,
    int* tag_len, uint8_t tag)
{
    if (input[*inOutIdx] != tag) {
        return -1;
    }
    (*inOutIdx)++;
    *tag_len = input[*inOutIdx];
    (*inOutIdx)++;
    if (*tag_len + *inOutIdx > inputSz) {
        return -1;
    }
    return 0;
}
#ifndef WOLFTPM2_NO_WOLFCRYPT
#include <wolfssl/wolfcrypt/asn.h>
#else
#define ASN_SEQUENCE     0x10
#define ASN_CONSTRUCTED  0x20
#define ASN_BIT_STRING   0x03
#define ASN_OCTET_STRING 0x04
#endif
static int RsaDecodeSignature(uint8_t** pInput, int inputSz)
{
    uint8_t* input = *pInput;
    int idx = 0;
    int digest_len = 0, algo_len, tot_len;

    /* sequence - total size */
    if (DecodeAsn1Tag(input, inputSz, &idx, &tot_len,
            ASN_SEQUENCE | ASN_CONSTRUCTED) != 0) {
        return -1;
    }

    /* sequence - algoid */
    if (DecodeAsn1Tag(input, inputSz, &idx, &algo_len,
            ASN_SEQUENCE | ASN_CONSTRUCTED) != 0) {
        return -1;
    }
    idx += algo_len; /* skip algoid */

    /* digest */
    if (DecodeAsn1Tag(input, inputSz, &idx, &digest_len,
            ASN_OCTET_STRING) != 0) {
        return -1;
    }
    /* return digest buffer pointer */
    *pInput = &input[idx];
    return digest_len;
}

int TPM2_EndorsementCertVerify_Example(void* userCtx, int argc, char *argv[])
{
    int rc = -1;
    WOLFTPM2_DEV dev;
    TPMS_NV_PUBLIC nvPublic;
    WOLFTPM2_KEY endorse;
    WOLFTPM2_KEY certPubKey;
    uint8_t* sigDigest;
    TPMT_PUBLIC publicTemplate;
    uint32_t nvIndex = 0x1c00002;
    WOLFTPM2_HASH hash;
    uint8_t hashBuf[TPM_MAX_DIGEST_SIZE];
    uint32_t hashSz = 0;
    uint8_t sig[SIG_SZ];
    int     sigSz = (int)sizeof(sig);

    XMEMSET(&endorse, 0, sizeof(endorse));
    XMEMSET(&nvPublic, 0, sizeof(nvPublic));
    XMEMSET(&certPubKey, 0, sizeof(certPubKey));

    if (argc >= 2) {
        if (XSTRCMP(argv[1], "-?") == 0 ||
            XSTRCMP(argv[1], "-h") == 0 ||
            XSTRCMP(argv[1], "--help") == 0) {
            usage();
            return 0;
        }
    }

    printf("Endorsement Certificate Verify\n");

    rc = wolfTPM2_Init(&dev, TPM2_IoCb, userCtx);
    if (rc != TPM_RC_SUCCESS) {
        printf("wolfTPM2_Init failed 0x%x: %s\n", rc, TPM2_GetRCString(rc));
        goto exit;
    }

    /* Get Endorsement Public Key template using NV index */
    rc = wolfTPM2_GetKeyTemplate_EKIndex(nvIndex, &publicTemplate);
    if (rc != 0) {
        printf("EK Index 0x%08x not valid\n", nvIndex);
        goto exit;
    }

    /* Create Endorsement Key */
    if (rc == 0) {
        /* Create Endorsement Key using EK auth policy */
        printf("Creating Endorsement Key\n");
        rc = wolfTPM2_CreatePrimaryKey(&dev, &endorse, TPM_RH_ENDORSEMENT,
            &publicTemplate, NULL, 0);
        if (rc != 0) goto exit;
        printf("Endorsement key loaded at handle 0x%08x\n",
            endorse.handle.hndl);

        /* Display EK public information */
        show_ek_public(&endorse.pub);
    }

    if (rc == 0) {
        /* Signature is last 512 bytes of certificate */
        /* Hash certificate minus 512 bytes */
        XMEMSET(&hash, 0, sizeof(hash));
        rc = wolfTPM2_HashStart(&dev, &hash, TPM_ALG_SHA384, NULL, 0);
        if (rc == 0) {
            rc = wolfTPM2_HashUpdate(&dev, &hash, kTpmEkCertRsa2048,
                sizeof(kTpmEkCertRsa2048)-SIG_SZ);
            if (rc == 0) {
                hashSz = sizeof(hashBuf);
                rc = wolfTPM2_HashFinish(&dev, &hash, hashBuf, &hashSz);
            }

            printf("Cert Hash: %d\n", hashSz);
            dump_hex_bytes(hashBuf, hashSz);
        }
    }

    if (rc == 0) {
        /* Import issuer certificate public key */
        certPubKey.pub.publicArea.type = TPM_ALG_RSA;
        certPubKey.pub.publicArea.nameAlg = TPM_ALG_SHA384;
        certPubKey.pub.publicArea.objectAttributes = (TPMA_OBJECT_decrypt);
        certPubKey.pub.publicArea.parameters.rsaDetail.keyBits = sizeof(kIssuerPubModulus) * 8;
        certPubKey.pub.publicArea.parameters.rsaDetail.exponent = 0x10001;
        certPubKey.pub.publicArea.parameters.rsaDetail.scheme.scheme = TPM_ALG_NULL;
        certPubKey.pub.publicArea.parameters.rsaDetail.scheme.details.anySig.hashAlg = TPM_ALG_SHA384;
        certPubKey.pub.publicArea.unique.rsa.size = sizeof(kIssuerPubModulus);
        XMEMCPY(certPubKey.pub.publicArea.unique.rsa.buffer, kIssuerPubModulus, sizeof(kIssuerPubModulus));
        certPubKey.pub.publicArea.parameters.rsaDetail.symmetric.algorithm = TPM_ALG_NULL;

        rc = wolfTPM2_LoadPublicKey(&dev, &certPubKey, &certPubKey.pub);

        /* TODO: Compare certificate public key with EK public key (like compare_ek_public) */
        /* Extract public key from certificate and parse ASN.1 and extract raw RSA exponent and modulus */

    }

    if (rc == 0) {
        /* RSA Public Decrypt signature (last 512 bytes of certificate )*/
        sigDigest = (uint8_t*)&kTpmEkCertRsa2048[sizeof(kTpmEkCertRsa2048)-SIG_SZ];
        rc = wolfTPM2_RsaEncrypt(&dev, &certPubKey,
            TPM_ALG_NULL, /* no padding */
            sigDigest, SIG_SZ,
            sig, &sigSz);
        if (rc != 0) {
            printf("RSA Public Failed!\n");
            goto exit;
        }
        printf("Decrypted Sig: %d\n", sigSz);
        dump_hex_bytes(sig, sigSz);
    }

    if (rc == 0) {
        sigDigest = sig;
        rc = RsaDecodeSignature(&sigDigest, sigSz);
    }
    if (rc == 0) {
        printf("Sig Hash: %d\n", hashSz);
        dump_hex_bytes(sigDigest, hashSz);

        /* Compare certificate hash with signature hash */
        if (memcmp(sigDigest, hashBuf, hashSz) == 0) {
            printf("Certificate signature is valid\n");
        }
        else {
            printf("Certificate signature is invalid!\n");
            rc = -1;
        }
    }

exit:

    wolfTPM2_UnloadHandle(&dev, &endorse.handle);
    wolfTPM2_Cleanup(&dev);

    return rc;
}

/******************************************************************************/
/* --- END TPM2.0 Endorsement certificate tool  -- */
/******************************************************************************/
#endif /* !WOLFTPM2_NO_WRAPPER */

#ifndef NO_MAIN_DRIVER
int main(int argc, char *argv[])
{
    int rc = -1;

#ifndef WOLFTPM2_NO_WRAPPER
    rc = TPM2_EndorsementCertVerify_Example(NULL, argc, argv);
#else
    printf("Wrapper code not compiled in\n");
    (void)argc;
    (void)argv;
#endif /* !WOLFTPM2_NO_WRAPPER */

    return rc;
}
#endif
